const favoriteBtn=document.getElementById("favoriteBtn"),favoriteIcon=document.getElementById("favoriteIcon");favoriteBtn.addEventListener("click",async t=>{const e=favoriteBtn.dataset.id;try{const t=await fetch("../back/router.php?action=toggle-favorite",{method:"POST",credentials:"same-origin",headers:{"Content-Type":"application/json","X-CSRF-TOKEN":getCsrfToken()},body:JSON.stringify({productId:e})}),a=await t.json();a.success?"add"===a.action?(favoriteBtn.classList.add("product-detail__wishlist--liked"),favoriteIcon.classList.remove("fa-regular"),favoriteIcon.classList.add("fa-solid")):(favoriteBtn.classList.remove("product-detail__wishlist--liked"),favoriteIcon.classList.remove("fa-solid"),favoriteIcon.classList.add("fa-regular")):showNotification(a.message,"red")}catch(t){console.error(t)}});